diff --git a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
index a4831ea7c11f..72bea44c239d 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
@@ -2888,7 +2888,16 @@ void VPPredInstPHIRecipe::execute(VPTransformState &State) {
   Instruction *ScalarPredInst =
       cast<Instruction>(State.get(getOperand(0), *State.Lane));
   BasicBlock *PredicatedBB = ScalarPredInst->getParent();
-  BasicBlock *PredicatingBB = PredicatedBB->getSinglePredecessor();
+  BasicBlock *PredicatingBB = nullptr;
+  // Try to find the predecessor block. First try getSinglePredecessor, which
+  // requires exactly one predecessor edge. If that fails, try
+  // getUniquePredecessor, which allows multiple edges from the same predecessor.
+  if (PredicatedBB->hasNPredecessors(1))
+    PredicatingBB = PredicatedBB->getSinglePredecessor();
+  else
+    PredicatingBB = PredicatedBB->getUniquePredecessor();
+  // If we still don't have a predecessor, we cannot create the PHI node.
+  // This should not happen for well-formed replicate regions.
   assert(PredicatingBB && "Predicated block has no single predecessor.");
   assert(isa<VPReplicateRecipe>(getOperand(0)) &&
          "operand must be VPReplicateRecipe");
