-  assert(PredicatingBB && "Predicated block has no single predecessor.");
+  BasicBlock *PredicatingBB = nullptr;
+  // Try to find the predecessor block. We need a single predecessor to create
+  // the PHI node as expected.
+  if (PredicatedBB->hasNPredecessors(1))
+    PredicatingBB = PredicatedBB->getSinglePredecessor();
+  // If we don't have a single predecessor, we cannot create the PHI node
+  // as expected. This can happen in rare cases where the predicated block
+  // has been transformed. In such cases, we skip creating the PHI node.
+  // This might lead to incorrect code if the value is actually needed.
+  if (!PredicatingBB) {
+    return;
+  }
   assert(isa<VPReplicateRecipe>(getOperand(0)) &&
