@@ -2888,7 +2888,18 @@ void VPPredInstPHIRecipe::execute(VPTransformState &State) {
   Instruction *ScalarPredInst =
       cast<Instruction>(State.get(getOperand(0), *State.Lane));
   BasicBlock *PredicatedBB = ScalarPredInst->getParent();
-  BasicBlock *PredicatingBB = PredicatedBB->getSinglePredecessor();
+  BasicBlock *PredicatingBB = nullptr;
+  // Try to find a suitable predecessor for the predicated block.
+  // First, try getSinglePredecessor which requires exactly one predecessor edge.
+  // If that fails, try to find any predecessor.
+  if (PredicatedBB->hasNPredecessors(1)) {
+    PredicatingBB = PredicatedBB->getSinglePredecessor();
+  } else {
+    auto PredBegin = pred_begin(PredicatedBB);
+    auto PredEnd = pred_end(PredicatedBB);
+    if (PredBegin != PredEnd)
+      PredicatingBB = *PredBegin;
+  }
   assert(PredicatingBB && "Predicated block has no single predecessor.");
   assert(isa<VPReplicateRecipe>(getOperand(0)) &&
          "operand must be VPReplicateRecipe");
